code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});

let i = 0;
let n, m;
let adj;
let input = [];
readline.on('line', line => {
    if(i == 0)
    {
        [n, m] = line.split(' ').map(num => parseInt(num));
        adj = new Array(n+1).fill(0).map(() => new Array(n+1).fill(0));
    }
    else
    {
        input.push(line.split(' ').map(num => parseInt(num)));
        if(i == m)
        {
            for(let j = 0; j < m; j++)
            {
                let u = input[j][0];
                let v = input[j][1];
                adj[u][v] = 1;
                adj[v][u] = 1; // remove this line for directed graph
            }
        }
    }
    i++;
});
